def _case_doc(case_id, title, citation, domain, facts, holding, significance, practical):
    return {
        "id": case_id,
        "title": title,
        "section": citation,
        "domain": domain,
        "content": f"""{title} is a landmark Supreme Court decision with citation {citation}. Facts and issue: {facts} The case required the Court to identify the controlling constitutional or statutory principle and to decide how far State power, social practice, criminal law, or institutional procedure could go without violating basic rights, fairness, or democratic structure.

Holding and ratio: {holding} The judgment is treated as authoritative not only because of the result but because of the doctrine it generated, refined, or rejected. In Indian legal practice, these cases often function as constitutional landmarks, shaping later interpretation across many statutes and procedural settings.

Significance: {significance} Later courts, tribunals, investigators, public authorities, and litigants use the case as precedent when similar fact patterns arise or when broader principles such as equality, liberty, dignity, due process, privacy, social justice, or fair criminal procedure are in issue. Practical application: {practical} For training a legal AI corpus, the case is important because it provides both black-letter holdings and the broader reasoning style of Indian constitutional and Supreme Court adjudication.""",
    }


CASE_LAW_CORPUS = [
    _case_doc(case_id='case_maneka_gandhi', title='Maneka Gandhi v. Union of India (1978)', citation='AIR 1978 SC 597', domain='Constitutional', facts="The Government impounded Maneka Gandhi's passport without furnishing full reasons, raising a challenge to arbitrary restriction on personal liberty and travel.", holding='The Supreme Court held that any procedure depriving a person of life or personal liberty under Article 21 must be fair, just, and reasonable, and must also withstand Article 14 and Article 19 scrutiny.', significance="The decision created the 'golden triangle' approach to Articles 14, 19, and 21, and transformed Article 21 from a narrow procedural guarantee into the source of numerous substantive rights.", practical='Lawyers cite the case whenever State action is arbitrary, procedurally unfair, or insufficiently reasoned, including in detention, administrative law, surveillance, and due process disputes.'),
    _case_doc(case_id='case_kesavananda_bharati', title='Kesavananda Bharati v. State of Kerala (1973)', citation='AIR 1973 SC 1461', domain='Constitutional', facts="A challenge to constitutional amendments affecting property and socio-economic reform led the Court to examine the scope of Parliament's power under Article 368.", holding='A thirteen-judge bench held that Parliament may amend the Constitution but cannot alter its basic structure or destroy its essential features.', significance='The basic structure doctrine became the central safeguard against constitutional authoritarianism and has since protected judicial review, democracy, federalism, secularism, and the rule of law.', practical='The case is invoked in amendment challenges, tribunal design litigation, federal disputes, and any attempt to reduce the core identity of the Constitution.'),
    _case_doc(case_id='case_shreya_singhal', title='Shreya Singhal v. Union of India (2015)', citation='(2015) 5 SCC 1', domain='Cyber', facts='Section 66A of the IT Act was challenged after repeated arrests for online speech, comments, and sharing of digital content.', holding='The Supreme Court struck down Section 66A as unconstitutional for vagueness, overbreadth, and chilling effect on free speech under Article 19(1)(a).', significance='It remains the leading Indian free-speech case for the internet era and also clarified the distinction between discussion, advocacy, and incitement.', practical='Courts and police are expected not to invoke Section 66A after this judgment; lawyers cite it in cases involving digital expression, blocking, takedowns, and online speech offences.'),
    _case_doc(case_id='case_vishaka', title='Vishaka v. State of Rajasthan (1997)', citation='AIR 1997 SC 3011', domain='Labour', facts="The gang rape of Bhanwari Devi and the absence of statutory workplace protection led women's groups to seek judicial safeguards against sexual harassment at work.", holding='The Supreme Court framed the Vishaka Guidelines under Articles 14, 15, 19, and 21, making them binding until legislation was enacted.', significance='The judgment directly led to the POSH framework and recognised workplace sexual harassment as a violation of equality, dignity, and safe working conditions.', practical="Employers, ICCs, labour advisers, and courts still read the POSH Act in the light of Vishaka's constitutional mandate."),
    _case_doc(case_id='case_dk_basu', title='D.K. Basu v. State of West Bengal (1997)', citation='(1997) 1 SCC 416', domain='Criminal', facts='The Court addressed widespread custodial violence and deaths, and the absence of consistent safeguards in arrest and detention practice.', holding='The Supreme Court laid down mandatory arrest and detention guidelines, including arrest memo requirements, information to relatives, medical examination, and production safeguards.', significance='The judgment constitutionalised arrest procedure and became the backbone of custodial rights jurisprudence under Articles 21 and 22.', practical='Bail lawyers, magistrates, and constitutional courts use D.K. Basu to test the legality of arrest, detention, and custodial conduct.'),
    _case_doc(case_id='case_arnesh_kumar', title='Arnesh Kumar v. State of Bihar (2014)', citation='(2014) 8 SCC 273', domain='Criminal', facts='The petitioner challenged routine arrests in Section 498A and similar offences punishable up to seven years, where arrest was being used automatically.', holding='The Court held that police cannot make automatic arrests and must satisfy Section 41 CrPC necessity criteria; magistrates must also scrutinise arrest justifications.', significance='The case reoriented arrest law from mechanical custody to necessity-based decision-making and strongly influenced anticipatory and regular bail practice.', practical='Police notices under Section 41A and defence arguments against routine arrest frequently rely on this judgment.'),
    _case_doc(case_id='case_indra_sawhney', title='Indra Sawhney v. Union of India (1992)', citation='1992 Supp (3) SCC 217', domain='Constitutional', facts='The Mandal Commission implementation raised questions on reservation for Other Backward Classes, equality, and the permissible extent of affirmative action.', holding='The Court upheld OBC reservation, recognised the creamy layer principle, and generally capped reservations at fifty percent subject to exceptional circumstances.', significance='It remains the core precedent on reservation policy, substantive equality, backward-class identification, and public employment under Articles 14, 15, and 16.', practical='Reservation disputes, educational admission challenges, and service matters regularly invoke Indra Sawhney.'),
    _case_doc(case_id='case_mc_mehta', title='M.C. Mehta v. Union of India', citation='Series of environmental decisions', domain='Constitutional', facts='A sequence of public interest cases on industrial pollution, hazardous industries, river pollution, vehicular emissions, and heritage protection came before the Court.', holding='The Court developed major environmental principles including absolute liability, polluter pays, precautionary principle, and the right to a clean environment under Article 21.', significance='These rulings transformed environmental governance and expanded PIL-based structural remedies in India.', practical='Environmental regulators, PIL litigants, and constitutional courts cite M.C. Mehta in pollution, industrial safety, climate-adjacent, and urban environmental disputes.'),
    _case_doc(case_id='case_shayara_bano', title='Shayara Bano v. Union of India (2017)', citation='(2017) 9 SCC 1', domain='Family', facts="The constitutional validity of instant triple talaq was challenged as arbitrary, discriminatory, and destructive of Muslim women's dignity.", holding='By a 3-2 majority, the Supreme Court invalidated instant triple talaq, paving the way for statutory reform.', significance='The decision marked a major intersection of gender justice, personal law, and constitutional review.', practical='Family law litigation on Muslim divorce and the 2019 statute is often read through the reasoning and social context of Shayara Bano.'),
    _case_doc(case_id='case_nalsa', title='National Legal Services Authority v. Union of India (2014)', citation='(2014) 5 SCC 438', domain='Constitutional', facts='Transgender persons sought legal recognition, equal citizenship, and protection from discrimination and exclusion.', holding='The Court recognised transgender persons as a third gender and affirmed their constitutional rights to dignity, equality, and self-identification.', significance='NALSA is the foundational Indian judgment on transgender rights and informed later legislation and anti-discrimination discourse.', practical='Identity documentation, reservation debates, prison rights, healthcare access, and discrimination cases cite NALSA.'),
    _case_doc(case_id='case_navtej_johar', title='Navtej Singh Johar v. Union of India (2018)', citation='(2018) 10 SCC 1', domain='Constitutional', facts='Consensual same-sex relations between adults were criminalised under Section 377 IPC, leading to constitutional challenge by LGBTQ+ petitioners.', holding='The Supreme Court decriminalised consensual same-sex relations between adults and held that sexual orientation is protected by dignity, privacy, equality, and expression.', significance='The judgment overruled Suresh Kumar Koushal and became a defining statement of constitutional morality and anti-stigma jurisprudence.', practical='It is central in LGBTQ+ rights, privacy, autonomy, and anti-discrimination litigation.'),
    _case_doc(case_id='case_joseph_shine', title='Joseph Shine v. Union of India (2018)', citation='(2019) 3 SCC 39', domain='Constitutional', facts='The adultery offence under Section 497 IPC treated women as property-like subjects and criminalised only the male outsider.', holding='The Supreme Court struck down Section 497 as unconstitutional for violating equality, dignity, and sexual autonomy.', significance='The ruling reinforced that criminal law cannot enforce patriarchal notions of marriage or deny women equal moral agency.', practical='Joseph Shine is cited in challenges to gendered criminal law and in debates on autonomy inside marriage.'),
    _case_doc(case_id='case_puttaswamy', title='Justice K.S. Puttaswamy v. Union of India (2017)', citation='(2017) 10 SCC 1', domain='Constitutional', facts='A challenge involving Aadhaar and broader surveillance concerns led to a reference on whether privacy is a fundamental right.', holding='A unanimous nine-judge bench held that privacy is a constitutionally protected fundamental right under Article 21 and related guarantees.', significance='The judgment anchors Indian data protection, bodily autonomy, decisional privacy, sexual autonomy, and informational privacy jurisprudence.', practical='Privacy, surveillance, reproductive autonomy, digital governance, and data protection disputes all rely heavily on Puttaswamy.'),
    _case_doc(case_id='case_adm_jabalpur', title='ADM Jabalpur v. Shiv Kant Shukla (1976)', citation='AIR 1976 SC 1207', domain='Constitutional', facts='During the Emergency, detainees sought habeas corpus despite suspension of enforcement of certain fundamental rights.', holding='The majority held that habeas corpus was not maintainable during the Emergency in the circumstances then prevailing, a position later repudiated.', significance='The case is remembered as a constitutional failure and is now effectively overruled in spirit and doctrine, especially after Puttaswamy.', practical='Modern constitutional argument uses ADM Jabalpur as a cautionary example of excessive judicial deference during emergencies.'),
    _case_doc(case_id='case_lily_thomas', title='Lily Thomas v. Union of India (2013)', citation='(2013) 7 SCC 653', domain='Constitutional', facts='The challenge concerned statutory protection allowing convicted legislators to retain their seats during appeal for a temporary period.', holding='The Court struck down the protective provision and held that convicted MPs and MLAs stand disqualified immediately upon conviction subject to statutory scheme.', significance='The judgment strengthened clean-governance and electoral accountability norms.', practical='Election law and disqualification disputes regularly cite Lily Thomas.'),
    _case_doc(case_id='case_aruna_shanbaug', title='Aruna Ramachandra Shanbaug v. Union of India (2011)', citation='(2011) 4 SCC 454', domain='Constitutional', facts='The case concerned withdrawal of life support for a nurse in a persistent vegetative state and the legality of passive euthanasia.', holding='The Court permitted passive euthanasia in limited situations under judicial oversight and laid down interim guidelines.', significance='It opened the constitutional conversation on end-of-life dignity, later deepened in Common Cause.', practical='Medical law, hospital ethics, and end-of-life decision-making initially relied on Aruna Shanbaug until a fuller framework emerged.'),
    _case_doc(case_id='case_common_cause', title='Common Cause v. Union of India (2018)', citation='(2018) 5 SCC 1', domain='Constitutional', facts='The Court reconsidered end-of-life autonomy and whether living wills and passive euthanasia could be constitutionally recognised.', holding='The Supreme Court recognised passive euthanasia and the validity of advance directives subject to safeguards.', significance='The judgment linked dignity in life with dignity in death under Article 21.', practical='Hospitals and families now look to this ruling for legal structure around living wills and withdrawal of life-sustaining treatment.'),
    _case_doc(case_id='case_bandhua_mukti_morcha', title='Bandhua Mukti Morcha v. Union of India (1984)', citation='(1984) 3 SCC 161', domain='Constitutional', facts='A public interest petition exposed bonded labour and inhuman working conditions in stone quarries.', holding='The Court treated bonded labour and exploitative working conditions as constitutional violations and expanded the remedial reach of PIL.', significance='The case reinforced that Article 21 includes dignified living conditions and that the Court can fashion continuing mandamus in social justice matters.', practical='Labour exploitation, trafficking, and bonded labour litigation still draw from this precedent.'),
    _case_doc(case_id='case_suresh_koushal', title='Suresh Kumar Koushal v. NAZ Foundation (2013)', citation='(2014) 1 SCC 1', domain='Constitutional', facts='The Delhi High Court had read down Section 377 to protect consensual adult same-sex relations, and that ruling was challenged.', holding='The Supreme Court reversed the Delhi High Court and restored the criminality of consensual same-sex relations, a view later overruled in Navtej Johar.', significance="The case is important primarily as a transitional judgment illustrating the Court's earlier reluctance before constitutional reversal.", practical='Current legal analysis discusses Koushal mainly to explain how Navtej Johar corrected its approach to dignity, equality, and minority rights.'),
    _case_doc(case_id='case_olga_tellis', title='Olga Tellis v. Bombay Municipal Corporation (1985)', citation='AIR 1986 SC 180', domain='Constitutional', facts='Pavement dwellers challenged eviction and demolition action that threatened both shelter and means of livelihood.', holding='The Court held that the right to livelihood is part of the right to life under Article 21, though eviction may still proceed according to law and fair procedure.', significance='The judgment expanded socio-economic dimensions of Article 21 and linked poverty, livelihood, and procedural fairness.', practical='Eviction, street-vendor, rehabilitation, and urban governance cases often rely on Olga Tellis.'),
    _case_doc(case_id='case_sp_gupta', title='S.P. Gupta v. Union of India (1981)', citation='1981 Supp SCC 87', domain='Constitutional', facts='Questions concerning judicial appointments, transfers, and access to governmental correspondence led to a broader debate on standing and public interest litigation.', holding='The Court greatly expanded locus standi and opened the door to PIL by allowing public-spirited persons to move the court for those unable to do so themselves.', significance='This decision helped transform Indian constitutional litigation from a purely private-rights model into a public-law accountability mechanism.', practical='Almost every modern PIL owes something to the procedural opening created by S.P. Gupta.'),
    _case_doc(case_id='case_hussainara_khatoon', title='Hussainara Khatoon v. State of Bihar (1979)', citation='AIR 1979 SC 1360', domain='Constitutional', facts='The Court confronted the plight of undertrial prisoners detained for years in Bihar without trial.', holding='It held that speedy trial is a fundamental right implicit in Article 21 and directed release and reform measures.', significance='The judgment reshaped undertrial jurisprudence, legal aid, and awareness of systemic delay as a constitutional injury.', practical='Bail, delay, undertrial release, and legal aid claims routinely cite Hussainara Khatoon.'),
    _case_doc(case_id='case_madhkar_narayan', title='State of Maharashtra v. Madhkar Narayan (1991)', citation='AIR 1991 SC 207', domain='Criminal', facts="The case concerned sexual violence and the degrading assumption that a woman of 'easy virtue' lacked legal protection of bodily integrity.", holding='The Court affirmed that even a woman of easy virtue is entitled to privacy, dignity, and protection against sexual assault.', significance='The case rejected stereotype-based reasoning and contributed to victim-centred sexual offence jurisprudence.', practical='It is cited to oppose character-based discrediting of complainants in sexual offence trials.'),
    _case_doc(case_id='case_shakti_vahini', title='Shakti Vahini v. Union of India (2018)', citation='(2018) 7 SCC 192', domain='Constitutional', facts='The Court addressed honour crimes and coercive actions by khap panchayats or families against consenting adult couples marrying across caste or religion lines.', holding='The Court issued preventive, remedial, and punitive guidelines to protect couples and curb honour-based violence.', significance='The judgment strongly affirmed autonomy in marriage choice under Articles 19 and 21.', practical='Police protection petitions by inter-caste and inter-faith couples frequently invoke Shakti Vahini.'),
    _case_doc(case_id='case_shah_bano', title='Mohd. Ahmed Khan v. Shah Bano Begum (1985)', citation='AIR 1985 SC 945', domain='Family', facts='A divorced Muslim woman sought maintenance under Section 125 CrPC after being repudiated by her husband.', holding='The Supreme Court held that Section 125 CrPC applies irrespective of religion and that a divorced Muslim woman unable to maintain herself is entitled to maintenance.', significance='The case became a national debate on gender justice, secular maintenance law, and personal law reform.', practical='Maintenance claims, Muslim family law disputes, and debates on personal law and constitutional equality continue to cite Shah Bano.'),
]
